namespace sv_8b3f2cdffff040c79727d17fbbcc0db8.Models;

public class PersonalInfo
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class ExperienceEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public int Years { get; set; }
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

public class WizardData
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = new();
    public List<ReferenceContact> References { get; set; } = new();
    public HashSet<int> CompletedSteps { get; set; } = new();
}

using System.Collections.Concurrent;
using sv_8b3f2cdffff040c79727d17fbbcc0db8.Models;

namespace sv_8b3f2cdffff040c79727d17fbbcc0db8.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by session ID.
/// Both the static layout and interactive pages resolve the same
/// session ID (via cookie) and use this store to read/write data.
/// </summary>
public class WizardDataStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId) =>
        _store.GetOrAdd(sessionId, _ => new WizardData());

    public WizardData? Get(string sessionId) =>
        _store.TryGetValue(sessionId, out var data) ? data : null;
}

using Microsoft.AspNetCore.Components;
using sv_8b3f2cdffff040c79727d17fbbcc0db8.Models;

namespace sv_8b3f2cdffff040c79727d17fbbcc0db8.Services;

/// <summary>
/// Base class for interactive wizard step pages.  Bridges the session ID
/// from static prerender (where HttpContext is available) into the
/// interactive render using PersistentComponentState.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected WizardDataStore Store { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    private PersistingComponentStateSubscription _subscription;

    protected string SessionId { get; private set; } = string.Empty;
    protected WizardData Data { get; private set; } = new();

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var sessionId))
        {
            // During prerender — read or create the cookie
            var context = HttpContextAccessor.HttpContext;
            sessionId = context?.Request.Cookies["WizardSession"];
            if (string.IsNullOrEmpty(sessionId))
            {
                sessionId = Guid.NewGuid().ToString();
                context?.Response.Cookies.Append("WizardSession", sessionId, new CookieOptions
                {
                    HttpOnly = true,
                    SameSite = SameSiteMode.Strict,
                    MaxAge = TimeSpan.FromHours(4)
                });
            }
        }

        SessionId = sessionId!;
        Data = Store.GetOrCreate(SessionId);
    }

    protected void NavigateTo(string url)
    {
        Nav.NavigateTo(url);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

