@inherits LayoutComponentBase
@inject sv_8b3f2cdffff040c79727d17fbbcc0db8.Services.WizardDataStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

@{
    var sessionId = HttpContextAccessor.HttpContext?.Request.Cookies["WizardSession"] ?? "";
    var data = string.IsNullOrEmpty(sessionId) ? null : Store.Get(sessionId);
    var completedSteps = data?.CompletedSteps ?? new HashSet<int>();

    var steps = new (string Url, string Label, int Number)[]
    {
        ("/apply/personal-info", "Personal Info", 1),
        ("/apply/experience",    "Experience",    2),
        ("/apply/references",    "References",    3),
        ("/apply/review",        "Review",        4),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    var currentStep = steps.FirstOrDefault(s =>
        currentPath.Equals(s.Url, StringComparison.OrdinalIgnoreCase)).Number;
    if (currentStep == 0) currentStep = 1;
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <strong>Step @currentStep of @steps.Length</strong>
        </div>

        <nav class="px-4 py-2">
            <div class="d-flex gap-2 align-items-center">
                @foreach (var step in steps)
                {
                    var isCurrent = step.Number == currentStep;
                    var isCompleted = completedSteps.Contains(step.Number);
                    var badgeClass = isCurrent ? "badge bg-primary"
                        : isCompleted ? "badge bg-success"
                        : "badge bg-secondary";

                    <a href="@step.Url" class="text-decoration-none d-flex align-items-center gap-1">
                        <span class="@badgeClass rounded-pill px-2 py-1">@step.Number</span>
                        <span class="@(isCurrent ? "fw-bold" : "")">@step.Label</span>
                    </a>

                    if (step.Number < steps.Length)
                    {
                        <span class="text-muted">›</span>
                    }
                }
            </div>

            <div class="progress mt-2" style="height: 6px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(currentStep * 100 / steps.Length)%">
                </div>
            </div>
        </nav>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

